"use client";

import { useEffect, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { ShoppingCart, Heart } from "lucide-react";
import { getImageUrl, getPlaceholderImage } from "@/lib/utils/image";

interface Product {
  id: number;
  name: string;
  slug: string;
  price: number;
  sale_price?: number;
  images: Array<{ image_url: string }>;
  stock_quantity: number;
}

interface DynamicProductsSectionProps {
  brandId: number;
  brandName: string;
}

export function DynamicProductsSection({ brandId, brandName }: DynamicProductsSectionProps) {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const apiUrl = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
        const response = await fetch(`${apiUrl}/api/products?brand_id=${brandId}&per_page=8`);
        
        if (response.ok) {
          const data = await response.json();
          setProducts(data.data || []);
        }
      } catch (error) {
        console.error("Error fetching products:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchProducts();
  }, [brandId]);

  if (loading) {
    return (
      <section className="bg-white py-16">
        <div className="mx-auto max-w-[1400px] px-4 md:px-6">
          <div className="text-center">
            <div className="inline-block h-8 w-8 animate-spin rounded-full border-4 border-gray-200 border-t-orange-500"></div>
            <p className="mt-4 text-gray-600">Loading products...</p>
          </div>
        </div>
      </section>
    );
  }

  if (products.length === 0) {
    return null;
  }

  return (
    <section className="bg-white py-16">
      <div className="mx-auto max-w-[1400px] px-4 md:px-6">
        {/* Section Header */}
        <div className="mb-12 text-center">
          <h2 className="mb-4 text-4xl font-bold text-gray-900 md:text-5xl">
            {brandName} <span className="text-orange-500">Products</span>
          </h2>
          <p className="text-lg text-gray-600">
            Explore our collection of premium {brandName} fitness equipment
          </p>
        </div>

        {/* Products Grid */}
        <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
          {products.map((product) => {
            const mainImage = product.images?.[0]?.image_url;
            const hasDiscount = product.sale_price && product.sale_price < product.price;
            const discountPercentage = hasDiscount
              ? Math.round(((product.price - product.sale_price!) / product.price) * 100)
              : 0;

            return (
              <Link
                key={product.id}
                href={`/product/${product.slug}`}
                className="group relative overflow-hidden rounded-xl border border-gray-200 bg-white transition-all hover:shadow-xl"
              >
                {/* Product Image */}
                <div className="relative aspect-square overflow-hidden bg-gray-100">
                  {mainImage ? (
                    <Image
                      src={getImageUrl(mainImage)}
                      alt={product.name}
                      fill
                      className="object-cover transition-transform duration-300 group-hover:scale-110"
                      onError={(e) => {
                        (e.target as HTMLImageElement).src = getPlaceholderImage();
                      }}
                    />
                  ) : (
                    <div className="flex h-full items-center justify-center">
                      <span className="text-gray-400">No image</span>
                    </div>
                  )}

                  {/* Discount Badge */}
                  {hasDiscount && (
                    <div className="absolute left-3 top-3 rounded-full bg-red-500 px-3 py-1 text-xs font-bold text-white">
                      -{discountPercentage}%
                    </div>
                  )}

                  {/* Stock Status */}
                  {product.stock_quantity === 0 && (
                    <div className="absolute inset-0 flex items-center justify-center bg-black/60">
                      <span className="rounded-lg bg-white px-4 py-2 text-sm font-semibold text-gray-900">
                        Out of Stock
                      </span>
                    </div>
                  )}

                  {/* Quick Actions */}
                  <div className="absolute right-3 top-3 flex flex-col gap-2 opacity-0 transition-opacity group-hover:opacity-100">
                    <button
                      onClick={(e) => {
                        e.preventDefault();
                        // Add to wishlist logic
                      }}
                      className="rounded-full bg-white p-2 shadow-lg transition-colors hover:bg-orange-500 hover:text-white"
                    >
                      <Heart className="h-4 w-4" />
                    </button>
                  </div>
                </div>

                {/* Product Info */}
                <div className="p-4">
                  <h3 className="mb-2 line-clamp-2 text-sm font-semibold text-gray-900 group-hover:text-orange-500">
                    {product.name}
                  </h3>

                  {/* Price */}
                  <div className="flex items-center gap-2">
                    {hasDiscount ? (
                      <>
                        <span className="text-lg font-bold text-orange-500">
                          ${product.sale_price?.toFixed(2)}
                        </span>
                        <span className="text-sm text-gray-500 line-through">
                          ${product.price.toFixed(2)}
                        </span>
                      </>
                    ) : (
                      <span className="text-lg font-bold text-gray-900">
                        ${product.price.toFixed(2)}
                      </span>
                    )}
                  </div>

                  {/* Add to Cart Button */}
                  <button
                    onClick={(e) => {
                      e.preventDefault();
                      // Add to cart logic
                    }}
                    disabled={product.stock_quantity === 0}
                    className="mt-3 flex w-full items-center justify-center gap-2 rounded-lg bg-orange-500 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-orange-600 disabled:cursor-not-allowed disabled:bg-gray-300"
                  >
                    <ShoppingCart className="h-4 w-4" />
                    {product.stock_quantity === 0 ? "Out of Stock" : "Add to Cart"}
                  </button>
                </div>
              </Link>
            );
          })}
        </div>

        {/* View All Button */}
        <div className="mt-12 text-center">
          <Link
            href={`/shop?brand=${brandId}`}
            className="inline-block rounded-lg bg-gradient-to-r from-orange-400 to-orange-500 px-8 py-3 font-semibold text-white transition-all hover:from-orange-500 hover:to-orange-600"
          >
            View All {brandName} Products
          </Link>
        </div>
      </div>
    </section>
  );
}
